mapper.select:
SELECT 
FROM securities_orders
WHERE member_id = #{memberId}
  AND idempotency_key = #{idempotencyKey}

mapper.update:
UPDATE securities_orders
SET status = #{status}
WHERE id = #{id}

UPDATE securities_orders
SET status = 'FAILED',
    failure_reason = #{failureReason}
WHERE id = #{id}
  AND status = 'REQUESTED'

UPDATE securities_orders
SET status = 'MANUAL_REVIEW',
    failure_reason = #{failureReason}
WHERE id = #{id}
  AND status IN ('REQUESTED', 'FUNDS_COMPLETED', 'COMPLETED', 'FAILED', 'CANCELED')

UPDATE securities_orders
SET status = 'REVERSED',
    failure_reason = #{failureReason},
    completed_at = #{completedAt}
WHERE id = #{id}
  AND status IN ('REQUESTED', 'FUNDS_COMPLETED')

mapper.select:
SELECT 
FROM securities_orders
WHERE member_id = #{memberId}
ORDER BY created_at DESC, id DESC
LIMIT #{limit}
